const item = $input.first().json;

const message = item.messages?.[0] || null;
const contact = item.contacts?.[0] || null;

if (!message) return [];

const tipo = message['type'];
let texto = '';

if (tipo === 'text')   texto = message['text']?.body ?? '';
if (tipo === 'button') texto = message['button']?.text ?? '';
if (tipo === 'interactive') {
  texto = message['interactive']?.button_reply?.title
       ?? message['interactive']?.list_reply?.title ?? '';
}

if (!texto) return [];

return [{
  json: {
    from:      message['from'],
    messageId: message['id'],
    tipo,
    texto,
    nombre: contact?.['profile']?.name ?? 'Cliente'
  }
}];
